Prompt Table PSP_SMSSYNC_FAILURE;
CREATE TABLE PSP_SMSSYNC_FAILURE
(
  SMSSYNC_FAILURE_SEQ    VARCHAR2(255 CHAR)     NOT NULL,
  VERSION                NUMBER(19)             NOT NULL,
  CREATOR_ID             VARCHAR2(30 CHAR),
  CREATED_DATE           TIMESTAMP(6)           NOT NULL,
  MODIFIER_ID            VARCHAR2(30 CHAR),
  MODIFIED_DATE          TIMESTAMP(6)           NOT NULL,
  REALM_ID               NUMBER(19)             DEFAULT -1                    NOT NULL,
  SOURCE_COMPANY_ID      VARCHAR2(50 CHAR),
  COMPANY_REALM_ID       NUMBER(19),
  SYNC_DIRECTION         VARCHAR2(255 CHAR),
  LAST_RETRY_TIME_STAMP  TIMESTAMP(6),
  STATUS                 VARCHAR2(255 CHAR),
  COUNT                  NUMBER(10),
  FAILURE_REASON         VARCHAR2(4000 CHAR)
)
NOPARALLEL;

ALTER TABLE PSP_SMSSYNC_FAILURE
 ADD CONSTRAINT C_PSP_SMSSYNC_FAILURE0
  CHECK (SYNC_DIRECTION IN('PSPToAS', 'ASToPSP'));

ALTER TABLE PSP_SMSSYNC_FAILURE
 ADD CONSTRAINT C_PSP_SMSSYNC_FAILURE1
  CHECK (STATUS IN('Pending', 'NeverRetry', 'Done', 'InProcess'));

ALTER TABLE PSP_SMSSYNC_FAILURE
 ADD PRIMARY KEY
  (SMSSYNC_FAILURE_SEQ, REALM_ID)
  USING INDEX;

